24	) : ViewModel() {
25	
26	    private val _uiState = MutableStateFlow(RecommendedActorsUiState())
27	    val uiState: StateFlow<RecommendedActorsUiState> = _uiState.asStateFlow()
28	
29	    private val bufferQueue = mutableListOf<Actor>()
30	    private val seenActorIds = mutableSetOf<String>()
31	
32	    init {
33	        loadInitialBatch()
34	    }
35	
36	    private fun loadInitialBatch() {
37	        viewModelScope.launch {
38	            _uiState.update { it.copy(isLoading = true, error = null) }
39	            repository.getRecommendedActors(limit = FETCH_SIZE).fold(
40	                onSuccess = { actors ->
41	                    val newActors = actors.filter { it.id !in seenActorIds }
42	                    bufferQueue.addAll(newActors)
43	                    updateDisplayedActors()
44	                    _uiState.update { it.copy(isLoading = false) }
45	                },
46	                onFailure = { e ->
47	                    _uiState.update { it.copy(isLoading = false, error = e.message) }
48	                }
49	            )
50	        }
51	    }
52	
53	    fun dismissActor(actorId: String) {
54	        seenActorIds.add(actorId)
55	        bufferQueue.removeAll { it.id == actorId }
56	        updateDisplayedActors()
57	        if (bufferQueue.size <= REFETCH_THRESHOLD) {
58	            fetchMoreActors()
59	        }
60	    }
61	
62	    fun followActor(actorId: String) {
63	        viewModelScope.launch {
64	            repository.followActor(actorId).fold(
